def calc(s):
    def helper(index):
        stack = []
        num = 0
        operator = '+'

        while index < len(s):
            char = s[index]

            if char == ' ':
                index += 1
                continue
            elif char.isdigit():
                num = num * 10 + int(char)
                index += 1
            elif char == '(':
                num, index = helper(index + 1)
            elif char == ')':
                if operator == '+':
                    stack.append(num)
                elif operator == '-':
                    stack.append(-num)
                return sum(stack), index + 1
            elif char in '+-':
                if operator == '+':
                    stack.append(num)
                elif operator == '-':
                    stack.append(-num)
                operator = char
                num = 0
                index += 1

        if operator == '+':
            stack.append(num)
        elif operator == '-':
            stack.append(-num)

        return sum(stack), index

    result, _ = helper(0)
    return result
