def decode_ways(s):
    if not isinstance(s, str) or s == "":
        return 0
    if any(c not in "0123456789" for c in s):
        return 0
    n = len(s)
    if s[0] == "0":
        return 0
    prev2, prev1 = 1, 1
    for i in range(2, n + 1):
        cur = 0
        if s[i - 1] != "0":
            cur += prev1
        if 10 <= int(s[i - 2:i]) <= 26:
            cur += prev2
        if cur == 0:
            return 0
        prev2, prev1 = prev1, cur
    return prev1
